const email = $json;

let tone = "professional";
let response = "Dear customer, thank you for contacting us. We have received your message and our team will review it as soon as possible.";

if (email.risk_level === "critical") {
  tone = "urgent";
  response = "Dear customer, we sincerely apologize for the inconvenience. Your issue has been escalated to our management team and will be handled with priority.";
} else if (email.risk_level === "high" || email.sentiment_label === "negative") {
  tone = "apologetic";
  response = "Dear customer, we are sorry for the negative experience. We understand your concern and our support team will review your request immediately.";
}

return [
  {
    json: {
      email_id: email.email_id,
      suggested_response: response,
      tone: tone,
      approval_status: "pending"
    }
  }
];
